import org.springframework.security.core.annotation.AuthenticationPrincipal;
import org.springframework.security.oauth2.jwt.Jwt;
import org.springframework.web.bind.annotation.*;
import org.springframework.security.access.prepost.PreAuthorize;
import org.springframework.beans.factory.annotation.Autowired;
import java.util.List;

@RestController
@RequestMapping("/api/payments")
public class PaymentController {
    @Autowired private PaymentService paymentService;

    @GetMapping
    @PreAuthorize("hasRole('MERCHANT')")
    public List<Payment> getPayments(@AuthenticationPrincipal Jwt jwt) {
        // Extract merchant_id from VALIDATED JWT claim:
        String merchantId = jwt.getClaimAsString("merchant_id");
        String plan       = jwt.getClaimAsString("plan");  // basic, gold, enterprise

        // WHY FROM JWT (not ?merchant_id=... request param):
        // Request params are controlled by the client — anyone can set ?merchant_id=MRC-002
        // JWT claims are signed by the auth server — tamper = signature failure → 401
        // merchantId from JWT = GUARANTEED to be the authenticated merchant's ID

        return paymentService.findByMerchantId(merchantId);
    }

    @GetMapping("/bulk-export")
    @PreAuthorize("hasRole('MERCHANT') and @planService.allowsBulkExport(authentication)")
    public byte[] bulkExport(@AuthenticationPrincipal Jwt jwt) {
        String merchantId = jwt.getClaimAsString("merchant_id");
        // planService checks if merchant's plan allows bulk export (enterprise only)
        return paymentService.exportAll(merchantId);
    }

    record Payment(String id, String merchantId, double amount, String status) {}
    interface PaymentService {
        List<Payment> findByMerchantId(String id);
        byte[] exportAll(String id);
    }
    interface PlanService { boolean allowsBulkExport(org.springframework.security.core.Authentication auth); }
}

