@Configuration
public class CustomJwtConverterConfig {

    @Bean
    public JwtAuthenticationConverter customJwtConverter() {
        // Custom converter: extract 'permissions' claim, set merchant_id as name
        JwtAuthenticationConverter converter = new JwtAuthenticationConverter();

        // Set principal name from 'merchant_id' claim (default is 'sub'):
        converter.setPrincipalClaimName("merchant_id");

        // Extract 'permissions' claim as authorities:
        converter.setJwtGrantedAuthoritiesConverter(jwt -> {
            List<String> permissions = jwt.getClaimAsStringList("permissions");
            if (permissions == null) return List.of();
            return permissions.stream()
                .map(p -> new SimpleGrantedAuthority("PERMISSION_" + p))
                .collect(Collectors.toList());
        });

        return converter;
    }
}

