import jakarta.servlet.*;
import jakarta.servlet.http.*;
import org.springframework.web.filter.OncePerRequestFilter;
import org.springframework.stereotype.Component;
import java.util.concurrent.*;
import java.util.concurrent.atomic.*;
import java.io.IOException;
import java.util.Base64;
import com.fasterxml.jackson.databind.ObjectMapper;

@Component
public class MerchantRateLimitFilter extends OncePerRequestFilter {
    private final ConcurrentHashMap<String, AtomicInteger> requestCounts = new ConcurrentHashMap<>();
    private final ObjectMapper mapper = new ObjectMapper();

    @Override
    protected void doFilterInternal(HttpServletRequest req, HttpServletResponse res,
                                    FilterChain chain) throws ServletException, IOException {
        String auth = req.getHeader("Authorization");
        if (auth != null && auth.startsWith("Bearer ")) {
            String token = auth.substring(7);
            String merchantId = extractMerchantId(token);

            if (merchantId != null) {
                // Simple in-memory counter (production: use Redis for distributed)
                AtomicInteger count = requestCounts.computeIfAbsent(
                    merchantId, k -> new AtomicInteger(0));

                if (count.incrementAndGet() > 100) {
                    res.setStatus(429);  // Too Many Requests
                    res.setHeader("Retry-After", "60");
                    res.getWriter().write("{\"error\":\"rate limit exceeded\",\"retryAfter\":60}");
                    return;
                }
            }
        }
        chain.doFilter(req, res);
    }

    @SuppressWarnings("unchecked")
    private String extractMerchantId(String jwt) {
        try {
            String[] parts = jwt.split("\\.");
            if (parts.length < 2) return null;
            String payload = new String(Base64.getUrlDecoder().decode(parts[1]));
            java.util.Map<String, Object> claims = mapper.readValue(payload, java.util.Map.class);
            return (String) claims.get("merchant_id");
        } catch (Exception e) { return null; }
    }
}

