public class CustomJwtDecoderConfig {

    @Bean
    public JwtDecoder jwtDecoder(
            org.springframework.security.oauth2.jose.jws.SignatureAlgorithm alg) {
        // Standard validators:
        var validators = new ArrayList<OAuth2TokenValidator<Jwt>>();
        validators.add(JwtValidators.createDefaultWithIssuer("https://auth.razorpay.com"));
