            JwtClaimNames.ISS, iss -> "https://auth.razorpay.com".equals(iss)));
        validators.add(new JwtClaimValidator<List<String>>(
            JwtClaimNames.AUD, aud -> aud != null && aud.contains("razorpay-api")));
        // Custom: merchant_id must be present:
