import jakarta.servlet.*;
import jakarta.servlet.http.*;
import org.springframework.web.filter.OncePerRequestFilter;
import org.springframework.stereotype.Component;
import org.springframework.security.core.context.SecurityContextHolder;
import org.springframework.security.oauth2.jwt.Jwt;
import org.springframework.security.oauth2.server.resource.authentication.JwtAuthenticationToken;
import org.slf4j.MDC;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import java.io.IOException;

@Component
public class JwtAuditFilter extends OncePerRequestFilter {
    private static final Logger audit = LoggerFactory.getLogger("AUDIT");

    @Override
    protected void doFilterInternal(HttpServletRequest req, HttpServletResponse res,
                                    FilterChain chain) throws ServletException, IOException {
        try {
            var auth = SecurityContextHolder.getContext().getAuthentication();
            if (auth instanceof JwtAuthenticationToken jwtAuth) {
                Jwt jwt = jwtAuth.getToken();
                MDC.put("merchant_id", jwt.getClaimAsString("merchant_id"));
                MDC.put("sub",         jwt.getSubject());
                MDC.put("method",      req.getMethod());
                MDC.put("path",        req.getRequestURI());
            }
            chain.doFilter(req, res);
            // Log after response (status code available now):
            audit.info("[AUDIT] merchant_id={} method={} path={} status={}",
                MDC.get("merchant_id"), req.getMethod(),
                req.getRequestURI(), res.getStatus());
        } finally {
            MDC.clear();  // ALWAYS clear MDC in finally (thread pool reuse!)
        }
    }
}

