import org.springframework.context.annotation.*;
import org.springframework.security.config.annotation.web.builders.HttpSecurity;
import org.springframework.security.config.annotation.method.configuration.EnableMethodSecurity;
import org.springframework.security.config.annotation.web.configuration.EnableWebSecurity;
import org.springframework.security.config.http.SessionCreationPolicy;
import org.springframework.security.oauth2.server.resource.authentication.*;
import org.springframework.security.core.authority.SimpleGrantedAuthority;
import org.springframework.web.bind.annotation.*;
import org.springframework.security.core.annotation.AuthenticationPrincipal;
import org.springframework.security.oauth2.jwt.Jwt;
import org.springframework.security.access.prepost.PreAuthorize;
import org.springframework.boot.test.autoconfigure.web.servlet.WebMvcTest;
import org.springframework.test.web.servlet.MockMvc;
import org.springframework.beans.factory.annotation.Autowired;
import static org.springframework.security.test.web.servlet.request.SecurityMockMvcRequestPostProcessors.jwt;
import static org.springframework.test.web.servlet.request.MockMvcRequestBuilders.*;
import static org.springframework.test.web.servlet.result.MockMvcResultMatchers.*;
import java.util.*;
import org.junit.jupiter.api.*;

@Configuration @EnableWebSecurity @EnableMethodSecurity
class SynthSecurityCfg {
    @Bean SecurityFilterChain chain(HttpSecurity h) throws Exception {
        return h.csrf(c->c.disable()).sessionManagement(s->s.sessionCreationPolicy(SessionCreationPolicy.STATELESS))
            .authorizeHttpRequests(a->a.requestMatchers("/actuator/health").permitAll().anyRequest().authenticated())
            .oauth2ResourceServer(o->o.jwt(j->j.jwtAuthenticationConverter(conv()))).build();
    }
    @Bean JwtAuthenticationConverter conv(){
        var c=new JwtAuthenticationConverter();
        c.setJwtGrantedAuthoritiesConverter(jwt->{
            List<String> r=jwt.getClaimAsStringList("roles");
            return r==null?List.of():r.stream().map(x->new SimpleGrantedAuthority("ROLE_"+x)).toList();
        }); return c;
    }
}

@RestController
class SynthApiCtrl {
    @GetMapping("/api/me") @PreAuthorize("isAuthenticated()")
    public Map<String,String> me(@AuthenticationPrincipal Jwt jwt){
        return Map.of("sub",jwt.getSubject(),"merchant",jwt.getClaimAsString("merchant_id"));
    }
    @GetMapping("/api/admin") @PreAuthorize("hasRole('ADMIN')")
    public String admin(){ return "admin-data"; }
}

